member.example:
This method require PinService.json file by Aleph.
-PinService.json file example.
{ "xxHPCC_DPIN_PMU_slcA_100ohm": 100, "xxHPCC_DPIN_PMU_slcA_2Kohm": 101, "xxHPCC_DPIN_PMU_slcA_50ohm1": 102 }
- Code example with PinMap implementation.
IDcResults dcResults = myDcTest.Execute();
dcResults.PrintToDatalogCompressFormatWithPinMap(myLimitsPerPin);
###########################################################################################################################################. Ituff format example to be printed.
2_tname_MyTP::MyDcTest_pc 2_strgval_3|100=0.199986|0.153711|0.177756|101=0.299988|102=0.399990 2_comnt_passPins_08004|08007|08001
###########################################################################################################################################.

remarks.code:
var sb = new StringBuilder();
const string lineFormatter = "| {0, -30} | {1, 14}  | {2, 9} | {3, 10} | {4, 8} |\n";
sb.Append($"Configuration : {this.Configuration}\n");
sb.Append("----------------------------------------------------------------------------------------\n");
sb.AppendFormat(lineFormatter, "Pin", "Measured Value", "Low Limit", "High Limit", "Result");
sb.Append("----------------------------------------------------------------------------------------\n");

foreach (var result in evaluatedResults.ResultsPerPin)
{
    foreach (var measurementsBlock in result.Value)
    {
        foreach (var singleMeasurement in measurementsBlock.Measurements)
        {
            sb.AppendFormat(lineFormatter, result.Key, singleMeasurement.ToString("G"), measurementsBlock.LowLimit.ToString("G"), measurementsBlock.HighLimit.ToString("G"), measurementsBlock.IsWithinLimits(singleMeasurement));
            sb.Append("----------------------------------------------------------------------------------------\n");
        }
    }
}

foreach (var pinGroupDcResults in this.ResultsPerGroupPerPin)
{
    msg.Append("Pingroup ").Append(pinGroupDcResults.Key).AppendLine(" results");
    foreach (var resultsPerPin in pinGroupDcResults.Value)
    {
        foreach (var pinResultBlock in resultsPerPin.Value)
        {
            foreach (var measurement in pinResultBlock.Measurements)
            {
                msg.Append("Pin").Append(resultsPerPin.Key).Append(" - ").AppendLine(measurement.ToString());
            }
        }
    }
}

member.summary:
Converts a list of string limits into a list of doubles, for example:
0.05mV, 0.07mV to List (double) { 0.00005, 0.00007 }
0.05m to List (double) { 0.00005 }.
